// redisClient.js
const Redis = require('ioredis');
const config = require('./config');

const redisClient = new Redis({
  host: config.redis.host,
  port: config.redis.port,
  password: config.redis.password,
  db: config.redis.db,
});

redisClient.on('connect', () => {
  console.log('Connected to Redis');
});

redisClient.on('error', (err) => {
  console.error('Redis Error:', err);
  // process.exit(1); // Exit if Redis connection is critical for app startup
});

module.exports = redisClient;

// app.js
const express = require('express');
const redisClient = require('./redisClient');
const config = require('./config');

const app = express();
app.use(express.json()); // Middleware to parse JSON request bodies

// Route to search keys by pattern
// Example: GET /search-keys?pattern=user:*
app.get('/search-keys', async (req, res) => {
  const { pattern } = req.query;

  if (!pattern) {
    return res.status(400).json({ error: 'Missing search pattern' });
  }

  try {
    // WARNING: KEYS command can block the Redis server for a long time
    // in large databases. For production, consider using SCAN for iterating keys.
    const keys = await redisClient.keys(pattern);
    res.json({ pattern, keys });
  } catch (error) {
    console.error('Error searching keys:', error);
    res.status(500).json({ error: 'Failed to search keys', details: error.message });
  }
});

// Route to execute arbitrary Redis commands
// Example: POST /execute-command
// Body: { "command": "SET mykey myvalue" }
// Body: { "command": "HGETALL user:123" }
// Body: { "command": "DEL mykey" }
app.post('/execute-command', async (req, res) => {
  const { command } = req.body;

  if (!command) {
    return res.status(400).json({ error: 'Missing Redis command' });
  }

  // Basic parsing: split command string into array of arguments
  // This is a simple split and might not handle complex quoted arguments perfectly.
  // For more robust parsing, consider dedicated command parsers if user input is complex.
  const args = command.split(/\s+/).filter(Boolean);

  if (args.length === 0) {
    return res.status(400).json({ error: 'Invalid Redis command format' });
  }

  try {
    // Call the Redis client method directly or use `call` for arbitrary commands
    // `redisClient.call` is suitable for executing commands by name and arguments.
    // Example: redisClient.call('SET', 'mykey', 'myvalue');
    // Example: redisClient.call('HGETALL', 'user:123');
    const result = await redisClient.call(...args);
    res.json({ command, result });
  } catch (error) {
    console.error('Error executing Redis command:', error);
    res.status(500).json({ error: 'Failed to execute Redis command', details: error.message });
  }
});

// Start the Express server
app.listen(config.server.port, () => {
  console.log(`Server running on port ${config.server.port}`);
  console.log(`Redis Host: ${config.redis.host}:${config.redis.port}`);
});